import React, { useEffect, useState } from "react";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import FAWButton from "../../../../component-widget/FAWButton";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWFileUpload from "../../../../component-widget/FAWFileUpload";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import { Box, IconButton, Typography } from "@mui/material";
import DeleteIcon from '@mui/icons-material/Delete';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';

export default function QueScormQuestionEditor({ data, onSave, onClose, saveRef, isDefaultLanguage = true, isDeployed = false, onChange }) {
  const [item, setItem] = useState(
    data || { name: "", text: "", required: false, validationMessage: "", horizontalLine: false, scormPackageId: "", fileName: "" }
  );
  const [uploadedFileName, setUploadedFileName] = useState("");
  const [showCharacterLimitWarning, setShowCharacterLimitWarning] = useState(false);
  const [fileQueue, setFileQueue] = useState([]);
  const [isUploading, setIsUploading] = useState(false);
  const [isDragOver, setIsDragOver] = useState(false);
  
  useEffect(()=>{ 
    if (data) {
      setItem(prev=>({ ...prev, ...data }));
      if (data.fileName) {
        setUploadedFileName(data.fileName);
        setShowCharacterLimitWarning(true);
      }
    }
  }, [data]);

  const handleChange = (field, value) => setItem(prev=>({ ...prev, [field]: value }));
  
  const processFile = (file) => {
    // Validate file type (matching legacy accept=".zip,.scorm")
    const allowedExtensions = ['.zip', '.scorm'];
    const fileExtension = '.' + file.name.split('.').pop().toLowerCase();
    
    if (!allowedExtensions.includes(fileExtension)) {
      alert('Please select a valid SCORM package (.zip or .scorm file)');
      return;
    }
    
    // Validate file size (optional - add reasonable limit)
    const maxSize = 100 * 1024 * 1024; // 100MB
    if (file.size > maxSize) {
      alert('File size too large. Please select a file smaller than 100MB.');
      return;
    }
    
    const fileName = file.name;
    const fileSize = (file.size / 1024).toFixed(2) + " kb";
    const fileType = file.type || "application/octet-stream";
    
    // Add file to queue instead of immediately setting as uploaded
    const fileInfo = {
      id: Date.now(),
      name: fileName,
      size: fileSize,
      type: fileType,
      file: file,
      status: "pending"
    };
    
    setFileQueue([fileInfo]);
    setShowCharacterLimitWarning(true);
  };

  const handleFileUpload = (event) => {
    const file = event.target.files[0];
    if (file) {
      processFile(file);
    }
  };

  const handleDragOver = (event) => {
    event.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (event) => {
    event.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (event) => {
    event.preventDefault();
    setIsDragOver(false);
    
    const files = event.dataTransfer.files;
    if (files.length > 0) {
      processFile(files[0]);
    }
  };

  const handleRemoveFile = () => {
    setFileQueue([]);
    setUploadedFileName("");
    setShowCharacterLimitWarning(false);
    handleChange("fileName", "");
    // Clear the file input
    const fileInput = document.getElementById('scorm-file-input');
    if (fileInput) {
      fileInput.value = "";
    }
  };

  const handleUploadFile = async () => {
    if (fileQueue.length === 0) return;
    
    setIsUploading(true);
    const fileInfo = fileQueue[0];
    
    try {
      // Create FormData for file upload (matching legacy AjaxFileUpload behavior)
      const formData = new FormData();
      formData.append('file', fileInfo.file);
      formData.append('questionType', 'ScormQuestionEditor');
      
      // Upload file to server endpoint (using QuestionnaireController)
      const response = await fetch('/Questionnaire/UploadScormFile', {
        method: 'POST',
        body: formData,
        headers: {
          // Don't set Content-Type, let browser set it with boundary for FormData
        }
      });
      
      if (!response.ok) {
        throw new Error(`Upload failed: ${response.statusText}`);
      }
      
      const result = await response.json();
      
      // Mark as uploaded and store filename (matching legacy session storage)
      setUploadedFileName(result.fileName);
      handleChange("fileName", result.fileName);
      handleChange("scormPackageId", result.scormPackageId);
      setFileQueue([]);
      
      // Update parent component state to enable Add Question button
      const updatedItem = { ...item, fileName: result.fileName, scormPackageId: result.scormPackageId };
      setItem(updatedItem);
      onChange?.(updatedItem);
      
      // Show success message
      
    } catch (error) {
      console.error("Upload failed:", error);
      // Show error message to user
      alert(`Upload failed: ${error.message}`);
    } finally {
      setIsUploading(false);
    }
  };

  const handleSave = () => {
    // Prevent save if version is deployed
    if (isDeployed) {
      return; // Save button will be disabled, so this shouldn't be called
    } 
    onSave?.(item); 
  };

  // Character limit from configuration (matching legacy)
  const characterLimit = 70; // Default, should come from config

  return (
    <EditorShell 
      onSave={handleSave} 
      onClose={onClose} 
      saveRef={saveRef}
    >
      <BaseQuestionFields item={item} onChange={(next)=> setItem(next)} isDefaultLanguage={isDefaultLanguage} isDeployed={isDeployed} questionType="ScormQuestionEditorItemType" />
      
      <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginTop: 8 }}>
        {/* File Upload Section */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          <label style={{ fontWeight: 'bold', fontSize: '14px' }}>SCORM Package Upload</label>
          
          {showCharacterLimitWarning && (
            <div style={{ 
              padding: '8px 12px', 
              backgroundColor: '#fff3cd', 
              border: '1px solid #ffeaa7', 
              borderRadius: '4px',
              fontSize: '12px',
              color: '#856404'
            }}>
              Note: Filenames are limited to {characterLimit} characters; if it exceeds, the file name will be automatically altered and stored.
            </div>
          )}
          
          {/* Drag and Drop Area */}
          <Box sx={{
            border: isDragOver ? '2px dashed #007bff' : '2px dashed #ccc',
            borderRadius: '8px',
            padding: '40px 20px',
            textAlign: 'center',
            backgroundColor: isDragOver ? '#e3f2fd' : '#fafafa',
            cursor: 'pointer',
            position: 'relative',
            transition: 'all 0.2s ease',
            '&:hover': {
              backgroundColor: '#f0f0f0',
              borderColor: '#999'
            }
          }}
          onClick={() => {
            const fileInput = document.getElementById('scorm-file-input');
            if (fileInput) fileInput.click();
          }}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
          >
            {/* Hidden file input */}
            <input
              id="scorm-file-input"
              type="file"
              accept=".zip,.scorm"
              onChange={handleFileUpload}
              disabled={isDeployed}
              style={{ display: 'none' }}
            />
            
            <Typography variant="body1" sx={{ color: isDragOver ? '#007bff' : '#666', fontSize: '16px' }}>
              {isDragOver ? 'Drop the file here' : 'Drop files here or click to browse'}
            </Typography>
            <Typography variant="body2" sx={{ color: '#999', fontSize: '12px', marginTop: 1 }}>
              Supported formats: .zip, .scorm
            </Typography>
          </Box>
          
          {/* File Queue Display */}
          {fileQueue.length > 0 && (
            <Box sx={{ marginTop: 2 }}>
              <Typography variant="body2" sx={{ marginBottom: 1, color: '#666' }}>
                {fileQueue.length} file(s) in queue.
              </Typography>
              
              {fileQueue.map((fileInfo) => (
                <Box key={fileInfo.id} sx={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'space-between',
                  padding: '8px 12px',
                  backgroundColor: '#f8f9fa',
                  border: '1px solid #dee2e6',
                  borderRadius: '4px',
                  marginBottom: 1
                }}>
                  <Box sx={{ flex: 1 }}>
                    <Typography variant="body2" sx={{ fontSize: '12px', color: '#495057' }}>
                      {fileInfo.type} - {fileInfo.size}
                    </Typography>
                    <Typography variant="body2" sx={{ fontSize: '12px', color: '#6c757d' }}>
                      ({fileInfo.status})
                    </Typography>
                  </Box>
                  
                  <Box sx={{ display: 'flex', gap: 1 }}>
                    <FAWButton
                      variant="outlined"
                      color="primary"
                      size="small"
                      onClick={handleRemoveFile}
                      sx={{
                        fontSize: '12px',
                        padding: '4px 8px',
                        minWidth: 'auto'
                      }}
                    >
                      Remove
                    </FAWButton>
                    
                    <FAWButton
                      variant="contained"
                      color="primary"
                      size="small"
                      onClick={handleUploadFile}
                      disabled={isUploading || isDeployed}
                      sx={{
                        fontSize: '12px',
                        padding: '4px 8px',
                        minWidth: 'auto'
                      }}
                    >
                      {isUploading ? 'Uploading...' : 'Upload'}
                    </FAWButton>
                  </Box>
                </Box>
              ))}
            </Box>
          )}
          
          {/* Uploaded File Display */}
          {uploadedFileName && (
            <Box sx={{ 
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              padding: '8px 12px', 
              backgroundColor: '#d4edda', 
              border: '1px solid #c3e6cb', 
              borderRadius: '4px',
              fontSize: '12px',
              color: '#155724'
            }}>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <CloudUploadIcon sx={{ fontSize: '16px' }} />
                <Typography variant="body2" sx={{ fontSize: '12px', color: '#155724' }}>
                  Uploaded: {uploadedFileName}
                </Typography>
              </Box>
              {!isDeployed && (
                <FAWButton
                  variant="outlined"
                  color="primary"
                  size="small"
                  onClick={handleRemoveFile}
                  sx={{
                    fontSize: '12px',
                    padding: '4px 8px',
                    minWidth: 'auto'
                  }}
                >
                  Remove
                </FAWButton>
              )}
            </Box>
          )}
        </div>

        {/* Training Completion Validation */}
        <FAWCheckbox
          label="Training Completion Validation"
          checked={!!item.failOnIncomplete}
          onChange={e=>handleChange("failOnIncomplete", e.target.checked)}
          disabled={isDeployed}
        />
      </div>
    </EditorShell>
  );
}



